(window.webpackJsonp=window.webpackJsonp||[]).push([[107],{734:function(n,e){n.exports="\x3c!-- \ntitle: XPath\nsort: \n--\x3e \n# XPath入门\n\n## 基本\n\n> / 代表根节点\n>\n> // 代表二次节点\n>\n> [1-n] 选择器\n>\n> @ 获取属性\n\n## 选择\n\n> `text()`：获取内容\n>\n> `normalize-space()`：存在空格\n>\n> `contains(func,text)`：包括\n>\n> `node()`：全部节点\n>\n> `parent::`\n>\n> `child::`：父子节点\n\n## 例子\n\n`/app/message[@name='xx']`"}}]);